{q:"Which of the following is a Sustainable Development Goal (SDG)?",o:["Zero Hunger","Colonizing Mars","Increasing Pollution","Developing Weapons"],a:"Zero Hunger",e:"SDG 2 aims to end hunger and achieve food security."},
{q:"What is the leading cause of death among children under 5 in Ghana?",o:["Cancer","Malaria","Diabetes","Car accidents"],a:"Malaria",e:"Malaria remains a major child killer, alongside pneumonia and diarrhoea."},
{q:"What is the role of the African Continental Free Trade Area (AfCFTA) headquartered in Accra?",o:["Military alliance","Single market for goods and services","Environmental protection","Sports regulation"],a:"Single market for goods and services",e:"AfCFTA aims to create the largest free trade area in the world."},
{q:"What is the name of the program under which Ghana's national ID card (Ghana Card) is issued?",o:["Passport Office","National Identification Authority (NIA)","ECG","SHEP"],a:"National Identification Authority (NIA)",e:"NIA registers citizens and issues the Ghana Card."},
{q:"What was the 'Year of Return 2019' a commemoration of?",o:["Independence","400th anniversary of the first enslaved Africans in the US","Republic Day","UN membership"],a:"400th anniversary of the first enslaved Africans in the US",e:"Marked the arrival of enslaved Africans in Jamestown, Virginia in 1619."},
{q:"What is the primary function of the Bank of Ghana (BoG)?",o:["Issuing loans to farmers","Regulating the monetary and financial system","Building schools","Printing textbooks"],a:"Regulating the monetary and financial system",e:"BoG is the central bank, controlling currency and monetary policy."},
{q:"How many members make up the African Union?",o:["15","27","55","65"],a:"55",e:"All 55 recognized African countries are AU members."},
{q:"What is the term for the exchange of cultural features resulting from continuous first-hand contact?",o:["Globalization","Acculturation","Innovation","Diffusion"],a:"Acculturation",e:"Acculturation involves changes in cultural patterns of either or both groups."},
{q:"Which colonial power ruled Ghana?",o:["France","Portugal","Britain","Germany"],a:"Britain",e:"The Gold Coast was a British colony until 1957."},
{q:"What is the highest court in Ghana's legal system?",o:["High Court","Court of Appeal","Supreme Court","Magistrate Court"],a:"Supreme Court",e:"The Supreme Court interprets the constitution and is the final court of appeal."},
{q:"Where is the University for Development Studies (UDS) located?",o:["Legon","Kumasi","Tamale","Cape Coast"],a:"Tamale",e:"UDS has campuses in the Northern, Upper East, and Upper West regions."},
{q:"What is the meaning of 'Ghana'?",o:["Warrior King","Gold Coast","Land of Gold","Freedom Land"],a:"Warrior King",e:"The name is derived from the ancient Ghana Empire, meaning 'Warrior King'."},
{q:"Which is NOT a natural resource of Ghana?",o:["Gold","Diamond","Petroleum","Mercury"],a:"Mercury",e:"Ghana produces gold, diamonds, bauxite, manganese, and oil, but not mercury."},
{q:"What is the main focus of the United Nations Convention on the Rights of the Child (UNCRC)?",o:["Child labour rights only","Protecting and promoting children's rights","Adult education","Space exploration"],a:"Protecting and promoting children's rights",e:"It sets out the civil, political, economic, social, and cultural rights of children."},
{q:"What is Galamsey?",o:["Legal large-scale mining","Illegal small-scale gold mining","Fishing method","Farming technique"],a:"Illegal small-scale gold mining",e:"Galamsey causes widespread environmental degradation in Ghana."},
{q:"What is the name of the Ghanaian festival celebrated by the Ga people?",o:["Aboakyer","Homowo","Hogbetsotso","Damba"],a:"Homowo",e:"Homowo means 'hooting at hunger' and is celebrated with Kpokpoi."},
{q:"What is the function of the Food and Drugs Authority (FDA) in Ghana?",o:["Regulating food and drugs for safety","Cooking food","Building hospitals","Selling food"],a:"Regulating food and drugs for safety",e:"FDA ensures public health and safety regarding food, drugs, and cosmetics."},
{q:"What is the term for people displaced within their own country due to conflict or disaster?",o:["Refugees","Migrants","Internally Displaced Persons (IDPs)","Aliens"],a:"Internally Displaced Persons (IDPs)",e:"IDPs have not crossed an international border."},
{q:"What is the purpose of the Ghana School Feeding Programme?",o:["To give money to farmers","Provide one hot meal a day to public school children","Build roads to schools","Train teachers"],a:"Provide one hot meal a day to public school children",e:"It aims to boost enrolment, retention, and nutrition."},
{q:"Which of the following is a key function of the National Media Commission (NMC)?",o:["Arresting journalists","Promoting press freedom and ensuring high media standards","Printing newspapers","Broadcasting"],a:"Promoting press freedom and ensuring high media standards",e:"NMC is independent, insulated from government control."},
{q:"What is the official name of the Ghanaian Parliament's Lower House?",o:["House of Commons","Senate","National Assembly","There is only one House (Unicameral)"],a:"There is only one House (Unicameral)",e:"Ghana has a unicameral legislature, simply called Parliament."},
{q:"What is the role of the Ministry of Finance?",o:["Foreign affairs","Managing public finances and economic policy","Education","Health"],a:"Managing public finances and economic policy",e:"It prepares the national budget and manages fiscal policy."},
{q:"What is the name of the initiative to plant millions of trees in Ghana?",o:["Operation Feed Yourself","Green Ghana Project","Operation Green Leaves","Forestry 2020"],a:"Green Ghana Project",e:"Green Ghana Day aims to restore degraded landscapes."},
{q:"Where is the headquarters of the United Nations?",o:["Geneva","New York","Paris","London"],a:"New York",e:"The UN Headquarters is in New York City, USA."}
